1	/**
2	 * Execute parallel LLM instrument runs via `claude --print`.
3	 *
4	 * Each run is independent: separate API call, independent sampling.
5	 * The runner spawns N parallel processes with full isolation (no tools,
6	 * no project config, sandboxed working directory).
7	 */
8	
9	import { execFile } from 'node:child_process';
10	import { mkdtempSync, writeFileSync } from 'node:fs';
11	import { join } from 'node:path';
12	import { tmpdir } from 'node:os';
13	import type { ExecutionConfig } from './types.ts';
14	
15	/** Maximum time per LLM run (5 minutes) */
16	const RUN_TIMEOUT_MS = 5 * 60 * 1000;
17	
18	export interface RunOutcome {
19	  index: number;
20	  success: boolean;
21	  response: string;
22	  error?: string;
23	}
24	
25	/**
26	 * Execute a single instrument run.
27	 *
28	 * Pipes the user message via stdin to avoid OS argument length limits.
29	 * The process runs in an empty tmpdir with all tools disabled.
30	 */
31	function executeRun(
32	  config: ExecutionConfig,
33	  systemPrompt: string,
34	  userMessage: string,
35	  sandboxDir: string,
36	  index: number,
37	): Promise<RunOutcome> {
38	  return new Promise((resolve) => {
39	    const args = [
40	      '--print',
41	      '--model', config.model,
42	      '--output-format', 'text',
